function injectEmployeeStyles(){if($('#employeeRuntimeStyles'))return;const style=document.createElement('style');style.id='employeeRuntimeStyles';style.textContent='.table-pagination{display:flex;align-items:center;justify-content:space-between;gap:12px;padding:12px 4px 0;color:var(--muted);font-size:11px}.pagination-controls{display:flex;align-items:center;gap:8px;flex-wrap:wrap}.pagination-controls label{display:flex;align-items:center;gap:6px}.pagination-controls select{border:1px solid var(--line);border-radius:7px;padding:7px 9px;background:#fff;font:11px Inter}.pagination-controls .btn{padding:7px 11px}.pagination-controls .btn:disabled{opacity:.45;cursor:not-allowed}.model-change-form .notice{margin-bottom:16px}.model-change-form fieldset{border:1px solid var(--line);border-radius:8px;padding:12px;display:flex;gap:16px;align-items:center;flex-wrap:wrap}.model-change-form fieldset legend{padding:0 6px;color:var(--muted);font-size:10px;font-weight:700}.loss-sections{display:grid;gap:18px;margin-top:18px}.loss-section{border:1px solid var(--line);border-radius:8px;overflow:hidden;background:#fff}.loss-section h3{margin:0;padding:12px 14px;background:#f8fafb;border-bottom:1px solid var(--line);font-size:13px}.loss-section table{width:100%;border-collapse:collapse}.loss-section th,.loss-section td{border-bottom:1px solid var(--line);padding:8px;vertical-align:top}.loss-section th{font-size:10px;color:var(--muted);text-align:left;background:#fbfcfd}.loss-section input{width:100%;min-width:90px;border:1px solid var(--line);border-radius:6px;padding:8px;font:11px Inter}.loss-time-input{max-width:80px}@media(max-width:900px){.loss-section{overflow-x:auto}.loss-section table{min-width:900px}}@media(max-width:600px){.table-pagination{align-items:flex-start;flex-direction:column}}';document.head.appendChild(style)}
function toast(message,error=false){const el=$('#toast');el.textContent=message;el.className=`toast show${error?' error':''}`;clearTimeout(toast.timer);toast.timer=setTimeout(()=>el.className='toast',3200)}
function navigate(view){$$('.view').forEach(x=>x.classList.remove('active'));$(`#${view}View`).classList.add('active');$$('.nav-item').forEach(x=>x.classList.toggle('active',x.dataset.view===view));$('#pageTitle').textContent=titles[view][0];$('#pageSubtitle').textContent=titles[view][1];$('#sidebar').classList.remove('open');if(view==='generated')renderHistory()}
function initNavigation(){$$('.nav-item').forEach(b=>b.onclick=()=>navigate(b.dataset.view));$$('[data-go]').forEach(b=>b.onclick=()=>navigate(b.dataset.go));$('#menuToggle').onclick=()=>$('#sidebar').classList.toggle('open')}
function renderTable(kind,rows){if(kind==='plan'){renderProductionTable(rows);return}if(kind==='employees'){renderEmployeeTable(rows);return}const head=$(`#${kind}Head`),body=$(`#${kind}Body`);if(!rows.length){head.innerHTML='';body.innerHTML='<tr><td><div class="empty">No hay resultados.</div></td></tr>';return}const headers=Object.keys(rows[0]).slice(0,10);head.innerHTML=`<tr>${headers.map(h=>`<th>${escapeHtml(h)}</th>`).join('')}</tr>`;body.innerHTML=rows.slice(0,500).map(r=>`<tr data-index="${state[kind].indexOf(r)}">${headers.map(h=>`<td title="${escapeHtml(r[h])}">${escapeHtml(r[h])}</td>`).join('')}</tr>`).join('')}
const escapeHtml=v=>String(v??'').replace(/[&<>"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[c]));

async function confirmDeletePassword(){
  const password=prompt('Escribe la contraseña para eliminar este documento:');
  if(password===null)return false;
  const digest=await crypto.subtle.digest('SHA-256',new TextEncoder().encode(password));
  const hash=[...new Uint8Array(digest)].map(value=>value.toString(16).padStart(2,'0')).join('');
  if(hash==='45a24631c7de203e7fd2ebc394a5f3d9b37bcccc0fa6e502a592ae3794be66d8')return true;
  toast('Contraseña incorrecta. No se eliminó el documento.',true);
  return false;
}

export class EmployeeAutocomplete{
  constructor({input,results,employees,placeholder='',fieldName='',selected=null,onSelect=()=>{}}){this.input=input;this.results=results;this.employees=typeof employees==='function'?employees:()=>employees||[];this.fieldName=fieldName;this.onSelect=onSelect;this.matches=[];this.activeIndex=-1;this.selected=null;if(placeholder)this.input.placeholder=placeholder;if(selected)this.setSelected(selected);input.addEventListener('input',()=>{this.selected=null;this.search()});input.addEventListener('keydown',event=>this.onKeydown(event));document.addEventListener('click',event=>{if(!this.results.contains(event.target)&&event.target!==this.input)this.close()})}
  search(){const query=normalizeColumnName(this.input.value);if(!query){this.close();return}this.matches=this.employees().filter(employee=>[employee.employeeNumber,employee.fullName,employee.area,employee.line].some(value=>normalizeColumnName(value).includes(query))).slice(0,10);this.activeIndex=-1;this.render()}
  render(){if(!this.matches.length){this.results.innerHTML='<div class="empty compact">Sin coincidencias.</div>';this.results.hidden=false;return}this.results.innerHTML=this.matches.map((employee,index)=>`<button type="button" class="autocomplete-item" data-index="${index}"><span class="autocomplete-avatar">${escapeHtml((employee.fullName||employee.employeeNumber).slice(0,2).toUpperCase())}</span><span class="autocomplete-copy"><strong>${escapeHtml(employee.employeeNumber)} · ${escapeHtml(employee.fullName)}</strong><small>${escapeHtml([employee.area,employee.shift,employee.line].filter(Boolean).join(' · '))}</small></span></button>`).join('');this.results.hidden=false;this.results.querySelectorAll('.autocomplete-item').forEach(button=>button.onclick=()=>this.select(this.matches[+button.dataset.index]))}
  onKeydown(event){if(this.results.hidden||!this.matches.length)return;if(event.key==='ArrowDown'){event.preventDefault();this.activeIndex=Math.min(this.activeIndex+1,this.matches.length-1)}else if(event.key==='ArrowUp'){event.preventDefault();this.activeIndex=Math.max(this.activeIndex-1,0)}else if(event.key==='Enter'&&this.activeIndex>=0){event.preventDefault();this.select(this.matches[this.activeIndex]);return}else if(event.key==='Escape'){this.close();return}else return;this.results.querySelectorAll('.autocomplete-item').forEach((item,index)=>item.classList.toggle('active',index===this.activeIndex))}
  setSelected(employee){this.selected=employee;this.input.value=employee?.fullName||employee?.employeeNumber||''}
  clear(){this.selected=null;this.input.value='';this.close()}
  select(employee){this.setSelected(employee);this.close();this.onSelect(employee);document.dispatchEvent(new CustomEvent('employee-selected',{detail:{employee,fieldName:this.fieldName}}));return employee}
  close(){this.results.hidden=true;this.activeIndex=-1}
}

function renderEmployeeTable(rows){state.employeeFiltered=rows;const head=$('#employeeHead'),body=$('#employeeBody'),totalPages=Math.max(1,Math.ceil(rows.length/state.employeePageSize));if(state.employeePage>totalPages)state.employeePage=totalPages;const start=(state.employeePage-1)*state.employeePageSize,pageRows=rows.slice(start,start+state.employeePageSize);head.innerHTML='<tr><th>Employee Number</th><th>Full Name</th><th>Shift</th><th>Line</th><th>Area</th><th>Position</th><th>Operation</th></tr>';if(!rows.length){body.innerHTML='<tr><td colspan="7"><div class="empty">No hay empleados que coincidan con los filtros.</div></td></tr>'}else{body.innerHTML=pageRows.map(employee=>`<tr><td><strong>${escapeHtml(employee.employeeNumber)}</strong></td><td>${escapeHtml(employee.fullName)}</td><td>${escapeHtml(employee.shift)}</td><td>${escapeHtml(employee.line)}</td><td>${escapeHtml(employee.area)}</td><td>${escapeHtml(employee.position)}</td><td>${escapeHtml(employee.operation)}</td></tr>`).join('')}renderEmployeePagination(rows.length,totalPages,start,pageRows.length)}
function renderEmployeePagination(total,totalPages,start,count){let box=$('#employeePagination');if(!box){const table=$('#employeeBody')?.closest('.table-card');if(!table)return;box=document.createElement('div');box.id='employeePagination';box.className='table-pagination';table.appendChild(box)}box.innerHTML=`<div class="pagination-info">${total?`${(start+1).toLocaleString()}-${(start+count).toLocaleString()} de ${total.toLocaleString()}`:'0 de 0'}</div><div class="pagination-controls"><label>Rows <select id="employeePageSize"><option value="25">25</option><option value="50">50</option><option value="100">100</option></select></label><button class="btn btn-light" id="employeePrevPage" type="button" ${state.employeePage<=1?'disabled':''}>Prev</button><span>${state.employeePage} / ${totalPages}</span><button class="btn btn-light" id="employeeNextPage" type="button" ${state.employeePage>=totalPages?'disabled':''}>Next</button></div>`;$('#employeePageSize').value=String(state.employeePageSize);$('#employeePageSize').onchange=event=>{state.employeePageSize=Number(event.target.value)||25;state.employeePage=1;renderEmployeeTable(state.employeeFiltered)};$('#employeePrevPage').onclick=()=>{state.employeePage=Math.max(1,state.employeePage-1);renderEmployeeTable(state.employeeFiltered)};$('#employeeNextPage').onclick=()=>{state.employeePage=Math.min(totalPages,state.employeePage+1);renderEmployeeTable(state.employeeFiltered)}}
function employeeOptions(field){return[...new Set(state.employees.map(employee=>String(employee[field]??'').trim()).filter(Boolean))].sort((a,b)=>a.localeCompare(b,undefined,{numeric:true}))}
function populateEmployeeFilters(){for(const[id,field,label]of[['shiftFilter','shift','Todos los turnos'],['employeeLineFilter','line','Todas las lineas'],['areaFilter','area','Todas las areas']]){const select=$(`#${id}`);select.innerHTML=`<option value="">${label}</option>${employeeOptions(field).map(value=>`<option value="${escapeHtml(value)}">${escapeHtml(value)}</option>`).join('')}`;select.disabled=false}}
function applyEmployeeFilters(resetPage=true){if(resetPage)state.employeePage=1;const query=normalizeColumnName($('#employeeSearch').value),shift=$('#shiftFilter').value,line=$('#employeeLineFilter').value,area=$('#areaFilter').value;let rows=state.employees.filter(employee=>!query||[employee.employeeNumber,employee.fullName,employee.line,employee.area,employee.position,employee.operation].some(value=>normalizeColumnName(value).includes(query)));if(shift)rows=rows.filter(employee=>String(employee.shift)===shift);if(line)rows=rows.filter(employee=>String(employee.line)===line);if(area)rows=rows.filter(employee=>String(employee.area)===area);renderEmployeeTable(rows);$('#employeeMeta').textContent=`${rows.length.toLocaleString()} de ${state.employees.length.toLocaleString()} empleados encontrados`}
function selectEmployee(employee){state.selectedEmployee=employee;const box=$('#selectedEmployeeSummary');box.hidden=false;box.innerHTML=`<div class="selected-heading"><h3>Empleado seleccionado</h3><span>Ready</span></div><div class="selected-grid"><div><small>Employee Number</small><strong>${escapeHtml(employee.employeeNumber)}</strong></div><div><small>Full Name</small><strong>${escapeHtml(employee.fullName)}</strong></div><div><small>Shift</small><strong>${escapeHtml(employee.shift)}</strong></div><div><small>Line</small><strong>${escapeHtml(employee.line)}</strong></div><div><small>Area</small><strong>${escapeHtml(employee.area)}</strong></div></div>`}

function scheduleLabel(schedule){return`${schedule.date} ${schedule.shift} · ${Number(schedule.quantity).toLocaleString('es-MX')}`}
function renderProductionTable(rows){const head=$('#planHead'),body=$('#planBody');head.innerHTML='<tr><th>Line</th><th>Rolling</th><th>Material Code</th><th>Internal Model</th><th>Customer Model</th><th>Material Type</th><th>Destination</th><th>Plan Quantity</th><th>Schedule</th><th></th></tr>';if(!rows.length){body.innerHTML='<tr><td colspan="10"><div class="empty">No hay registros que coincidan con los filtros.</div></td></tr>';return}body.innerHTML=rows.slice(0,1000).map(record=>`<tr><td>${escapeHtml(record.line)}</td><td><strong>${escapeHtml(record.rolling)}</strong></td><td>${escapeHtml(record.materialCode)}</td><td>${escapeHtml(record.internalModel)}</td><td>${escapeHtml(record.customerModel)}</td><td>${escapeHtml(record.materialType)}</td><td>${escapeHtml(record.destination)}</td><td>${escapeHtml(record.planQuantity)}</td><td class="schedule-list">${record.schedules.length?record.schedules.map(schedule=>`<span class="schedule-chip">${escapeHtml(scheduleLabel(schedule))}</span>`).join(''):'-'}</td><td><button class="btn btn-primary select-record" data-record-id="${escapeHtml(record.id)}">Select</button></td></tr>`).join('');body.querySelectorAll('.select-record').forEach(button=>button.onclick=()=>selectProductionRecord(state.plan.find(record=>record.id===button.dataset.recordId)))}
function selectProductionRecord(record,scheduleIndex=0){if(!record)return;state.currentProductionRecord=record;state.selectedSchedule=record.schedules[scheduleIndex]||null;renderSelectedRecord();document.dispatchEvent(new CustomEvent('production-record-selected',{detail:{record:state.currentProductionRecord,selectedSchedule:state.selectedSchedule}}));toast('Registro de produccion seleccionado')}
const productionAdjustmentFields=[['line','Line'],['materialType','Material Type'],['destination','Destination'],['brand','Brand'],['peDoc','PE Doc'],['orderQty','Order Qty'],['planQuantity','Plan Quantity'],['productionDate','Production Date'],['workOrderNo','Work Order No.'],['plannedStartTime','Planned Start Time'],['plannedEndTime','Planned End Time'],['orderRemarks','Order Remarks'],['priority','Priority'],['productionStatus','Production Status'],['planningStatus','Planning Status'],['scheduleStatus','Schedule Status'],['remark','Remark']];
function adjustmentEditorMarkup(record){const field=record.selectedAdjustmentField||Object.keys(record.manualAdjustments||{})[0]||'line',label=productionAdjustmentFields.find(item=>item[0]===field)?.[1]||field,original=record.importedRaw?.[field]??'',effective=record.raw?.[field]??'',active=Object.hasOwn(record.manualAdjustments||{},field),type=field==='productionDate'?'date':(['orderQty','planQuantity'].includes(field)?'number':'text');return`<div class="production-adjustment"><div class="adjustment-title"><div><h4>Ajuste manual</h4><small>El valor importado se conserva; la página muestra el valor efectivo.</small></div>${active?'<span>Ajuste activo</span>':''}</div><div class="adjustment-values"><div><small>Importado · ${escapeHtml(label)}</small><strong id="adjustmentImportedValue">${escapeHtml(original||'—')}</strong></div><div><small>Efectivo</small><strong id="adjustmentEffectiveValue">${escapeHtml(effective||'—')}</strong></div></div><div class="adjustment-form"><label>Campo<select id="adjustmentField">${productionAdjustmentFields.map(([value,text])=>`<option value="${value}" ${value===field?'selected':''}>${escapeHtml(text)}</option>`).join('')}</select></label><label>Nuevo valor<input id="adjustmentValue" type="${type}" value="${escapeHtml(effective)}"></label><label class="adjustment-reason">Motivo<input id="adjustmentReason" placeholder="Motivo obligatorio"></label><div class="adjustment-actions"><button class="btn btn-light" id="retireProductionAdjustment" type="button" ${active?'':'disabled'}>Retirar ajuste</button><button class="btn btn-primary" id="saveProductionAdjustment" type="button">Guardar ajuste</button></div></div></div>`}
async function reloadSelectedProductionRecord(lotId){const plan=await dataService.getProductionPlanRows();if(!plan?.rows)throw new Error('No fue posible recargar Production Plan.');renderProductionDataset(plan);const record=state.plan.find(item=>item.id===lotId);if(record)selectProductionRecord(record);return record}
async function saveSelectedProductionAdjustment(){const record=state.currentProductionRecord,field=$('#adjustmentField').value,value=$('#adjustmentValue').value,reason=$('#adjustmentReason').value,button=$('#saveProductionAdjustment');button.disabled=true;try{await dataService.saveProductionPlanAdjustment(record.id,field,value,reason);await reloadSelectedProductionRecord(record.id);toast('Ajuste manual guardado y aplicado como valor efectivo')}catch(error){toast(error.message,true);button.disabled=false}}
async function retireSelectedProductionAdjustment(){const record=state.currentProductionRecord,field=$('#adjustmentField').value,button=$('#retireProductionAdjustment');button.disabled=true;try{await dataService.retireProductionPlanAdjustment(record.id,field);await reloadSelectedProductionRecord(record.id);toast('Ajuste retirado; se restauró el valor importado')}catch(error){toast(error.message,true);button.disabled=false}}
function renderSelectedRecord(){const record=state.currentProductionRecord,box=$('#selectedProductionSummary');if(!record){box.hidden=true;return}box.hidden=false;box.innerHTML=`<div class="selected-heading"><h3>Registro seleccionado</h3><span>Ready</span></div><div class="selected-grid"><div><small>Rolling / Order</small><strong>${escapeHtml(record.rolling||record.orderNo)}</strong></div><div><small>Material Code</small><strong>${escapeHtml(record.materialCode)}</strong></div><div><small>Internal Model</small><strong>${escapeHtml(record.internalModel)}</strong></div><div><small>Customer Model</small><strong>${escapeHtml(record.customerModel)}</strong></div><div><small>Destination</small><strong>${escapeHtml(record.destination)}</strong></div></div>${record.schedules.length?`<div class="schedule-picker"><label>Selected schedule</label><select id="selectedScheduleInput">${record.schedules.map((schedule,index)=>`<option value="${index}" ${schedule===state.selectedSchedule?'selected':''}>${escapeHtml(scheduleLabel(schedule))}</option>`).join('')}</select></div>`:'<div class="schedule-picker"><label>Sin programacion disponible</label></div>'}${adjustmentEditorMarkup(record)}`;const picker=$('#selectedScheduleInput');if(picker)picker.onchange=()=>selectProductionRecord(record,+picker.value);$('#adjustmentField').onchange=event=>{record.selectedAdjustmentField=event.target.value;renderSelectedRecord()};$('#saveProductionAdjustment').onclick=saveSelectedProductionAdjustment;$('#retireProductionAdjustment').onclick=retireSelectedProductionAdjustment}
function uniqueOptions(field){return[...new Set(state.plan.map(record=>String(record[field]??'').trim()).filter(Boolean))].sort((a,b)=>a.localeCompare(b,undefined,{numeric:true}))}
function populatePlanFilters(){for(const[id,field,label]of[['lineFilter','line','Todas las lineas'],['modelFilter','internalModel','Todos los modelos'],['destinationFilter','destination','Todos los destinos']]){const select=$(`#${id}`);select.innerHTML=`<option value="">${label}</option>${uniqueOptions(field).map(value=>`<option value="${escapeHtml(value)}">${escapeHtml(value)}</option>`).join('')}`;select.disabled=false}}
function applyPlanFilters(){const query=$('#planSearch').value,line=$('#lineFilter').value,model=$('#modelFilter').value,destination=$('#destinationFilter').value;let rows=filterRows(state.plan,query);if(line)rows=rows.filter(record=>String(record.line)===line);if(model)rows=rows.filter(record=>String(record.internalModel)===model);if(destination)rows=rows.filter(record=>String(record.destination)===destination);renderProductionTable(rows);$('#planMeta').textContent=`${rows.length.toLocaleString()} de ${state.plan.length.toLocaleString()} registros`}

function renderProductionDataset(database){state.plan=database.rows||[];renderTable('plan',state.plan);$('#planSearch').disabled=false;$('#planMeta').textContent=`${state.plan.length.toLocaleString()} registros · origen: ${database.source}${database.offline?' (caché offline)':''}`;$('#planCount').textContent=state.plan.length.toLocaleString();$('#planStatus').textContent=database.metadata?.fileName||'Production Plan · Supabase';populatePlanFilters();refreshMaterialLookup()}
function importStatusLabel(status){return{uploaded:'Cargado',staging:'Preparando',invalid:'Bloqueado',ready:'Listo para aplicar',applying:'Aplicando',applied:'Aplicado',cancelled:'Cancelado',failed:'Error'}[status]||status}
async function renderProductionImportPreview(value){const preview=value?.conflicts?value:await dataService.getProductionPlanImport(value.id),box=$('#productionImportPreview'),status=$('#productionImportStatus'),apply=$('#applyProductionImport'),size=preview.source_file_versions?.size_bytes||value.sizeBytes||0;state.pendingProductionImport=preview;box.hidden=false;$('#productionImportFile').textContent=`${preview.source_file_versions?.original_name||value.fileName||'Production Plan'} · ${Number(size).toLocaleString('es-MX')} bytes · versión ${preview.source_file_versions?.version||value.sourceVersion||'-'}`;status.textContent=importStatusLabel(preview.status);status.className=`import-status ${preview.status}`;$$('[data-import-count]').forEach(node=>node.textContent=Number(preview[node.dataset.importCount]||0).toLocaleString('es-MX'));const conflicts=preview.conflicts||[],conflictBox=$('#productionImportConflicts');conflictBox.hidden=!conflicts.length;conflictBox.innerHTML=conflicts.slice(0,30).map(conflict=>`<div class="import-conflict"><span><strong>${escapeHtml(conflict.conflict_type)}</strong>${conflict.field_name?` · ${escapeHtml(conflict.field_name)}`:''}</span><span>${escapeHtml(conflict.severity)}</span></div>`).join('')+(conflicts.length>30?`<small>Y ${(conflicts.length-30).toLocaleString('es-MX')} conflictos más.</small>`:'');apply.disabled=preview.status!=='ready'||Number(preview.blocking_conflict_count)>0||Number(preview.rejected_count)>0;return preview}
async function stageProductionPlan(file,parsed){if(!dataService.stageProductionPlanImport)return null;const auth=await dataService.getAuthState?.();if(!auth?.authenticated)return null;$('#planDriveStatus').textContent='Subiendo a Supabase…';const preview=await dataService.stageProductionPlanImport(file,parsed);await renderProductionImportPreview(preview);$('#planDriveStatus').textContent=preview.status==='ready'?'Pendiente de aplicar':'Importación bloqueada';return preview}
async function applyPendingProductionImport(){const preview=state.pendingProductionImport;if(!preview)return;const button=$('#applyProductionImport');button.disabled=true;button.textContent='Aplicando…';try{const result=await dataService.applyProductionPlanImport(preview.id);await renderProductionImportPreview({...preview,...result,status:'applied',conflicts:preview.conflicts||[]});if(state.pendingProductionFile){await dataService.replaceProductionPlan(state.pendingProductionFile);state.pendingProductionFile=null}if(result.plan){renderProductionDataset(result.plan);const ui=activeUi('plan');ui.name.textContent=result.plan.metadata?.fileName||'Production Plan · Supabase';ui.date.textContent=new Date(result.plan.metadata?.uploadedAt||Date.now()).toLocaleString('es-MX');ui.status.textContent=`Supabase · activo · v${result.plan.metadata?.version||'-'}`}toast(result.alreadyApplied?'La versión ya estaba aplicada':'Production Plan aplicado correctamente')}catch(error){toast(error.message,true);await renderProductionImportPreview(preview).catch(()=>{})}finally{button.textContent='Aplicar versión'}}
async function cancelPendingProductionImport(){const preview=state.pendingProductionImport;if(!preview)return;const button=$('#cancelProductionImport');button.disabled=true;try{const cancelled=await dataService.cancelProductionPlanImport(preview.id);await renderProductionImportPreview({...preview,...cancelled,conflicts:preview.conflicts||[]});toast('Importación cancelada; el archivo queda marcado para limpieza posterior');await fetchActiveResource('plan')}catch(error){toast(error.message,true)}finally{button.disabled=false}}

async function loadFile(file,kind,persist=false){if(!file)return;try{if(persist){if(kind==='plan')await dataService.uploadProductionPlan(file);else await dataService.uploadEmployeeDatabase(file)}const result=kind==='plan'?await readProductionPlan(file):kind==='employees'?await readEmployeeDatabase(file):await readExcel(file);state[kind]=result.rows;state[`${kind}File`]=result;if(kind==='employees')state.employeePage=1;renderTable(kind,result.rows);$(`#${kind}Search`).disabled=false;if(kind==='plan'){$('#planFileName').textContent=result.fileName;$('#planLoadedAt').textContent=new Date(result.loadedAt).toLocaleString('es-MX');$('#planMeta').textContent=`${result.rows.length.toLocaleString()} registros · Hoja: ${result.sheetName} · Encabezado: fila ${result.headerRow}`;$('#planCount').textContent=result.rows.length.toLocaleString();$('#planStatus').textContent=result.fileName;populatePlanFilters();refreshMaterialLookup()}else{$('#employeeFileName').textContent=result.fileName;$('#employeeLoadedAt').textContent=new Date(result.loadedAt).toLocaleString('es-MX');$('#employeeMeta').textContent=`${result.rows.length.toLocaleString()} empleados · ${result.duplicates.toLocaleString()} duplicados eliminados · ${result.rejected||0} rechazados · Hoja: ${result.sheetName} · Encabezado: fila ${result.headerRow}`;$('#employeeCount').textContent=result.rows.length.toLocaleString();$('#employeeStatus').textContent=result.fileName;populateEmployeeFilters()}toast(`${file.name} cargado correctamente`);return result}catch(e){const prefix=kind==='plan'?'plan':'employee';$(`#${prefix}Meta`).textContent=e.message;$(`#${prefix}Head`).innerHTML='';$(`#${prefix}Body`).innerHTML=`<tr><td><div class="empty">${escapeHtml(e.message)}</div></td></tr>`;toast(e.message,true);throw e}}
function initImports(){$('#planInput').onchange=e=>loadFile(e.target.files[0],'plan',true);$('#employeeInput').onchange=e=>loadFile(e.target.files[0],'employees',true);$('#planSearch').oninput=applyPlanFilters;['lineFilter','modelFilter','destinationFilter'].forEach(id=>$(`#${id}`).onchange=applyPlanFilters);$('#employeeSearch').addEventListener('input',()=>applyEmployeeFilters(true));['shiftFilter','employeeLineFilter','areaFilter'].forEach(id=>$(`#${id}`).onchange=()=>applyEmployeeFilters(true));new EmployeeAutocomplete({input:$('#employeeSearch'),results:$('#employeeAutocompleteResults'),employees:()=>state.employees,placeholder:'Buscar numero, nombre, area o linea...',fieldName:'Employees search',onSelect:selectEmployee});const dz=$('#planDrop');dz.onclick=()=>$('#planInput').click();['dragenter','dragover'].forEach(ev=>dz.addEventListener(ev,e=>{e.preventDefault();dz.classList.add('drag')}));['dragleave','drop'].forEach(ev=>dz.addEventListener(ev,e=>{e.preventDefault();dz.classList.remove('drag')}));dz.addEventListener('drop',e=>replaceActiveResource('plan',e.dataTransfer.files[0]))}

function activeUi(kind){return kind==='plan'?{name:$('#planFileName'),date:$('#planLoadedAt'),status:$('#planDriveStatus'),message:'No active production plan found'}:{name:$('#employeeFileName'),date:$('#employeeLoadedAt'),status:$('#employeeDriveStatus'),message:'No active employee database found'}}
async function fetchActiveResource(kind){const ui=activeUi(kind);ui.status.textContent='Loading';try{if(kind==='plan'&&dataService.getProductionPlanRows){const database=await dataService.getProductionPlanRows();if(database?.rows){renderProductionDataset(database);ui.name.textContent=database.metadata?.fileName||'Production Plan · Supabase';ui.date.textContent=database.metadata?.uploadedAt?new Date(database.metadata.uploadedAt).toLocaleString('es-MX'):'-';ui.status.textContent=database.offline?'Supabase · caché offline':'Supabase · activo';state.planActiveMetadata=database.metadata||{};return database}}if(kind==='employees'&&dataService.getEmployees){const database=await dataService.getEmployees();if(database?.rows){state.employees=database.rows;state.employeePage=1;renderTable('employees',database.rows);$('#employeesSearch').disabled=false;$('#employeeMeta').textContent=`${database.rows.length.toLocaleString()} empleados · origen: ${database.source}${database.offline?' (caché sin conexión)':''}`;$('#employeeCount').textContent=database.rows.length.toLocaleString();$('#employeeStatus').textContent=database.metadata?.fileName||'Supabase';populateEmployeeFilters();ui.name.textContent=database.metadata?.fileName||'Employee Database · Supabase';ui.date.textContent=database.metadata?.uploadedAt?new Date(database.metadata.uploadedAt).toLocaleString('es-MX'):'-';ui.status.textContent=database.offline?'Supabase · caché offline':'Supabase · activo';state.employeesActiveMetadata=database.metadata||{};return database}}const active=kind==='plan'?await dataService.getActiveProductionPlan():await dataService.getActiveEmployeeDatabase();if(!active){ui.name.textContent=ui.message;ui.date.textContent='-';ui.status.textContent='Not found';return null}await loadFile(active.file,kind,false);const metadata=active.metadata||{};ui.name.textContent=metadata.fileName||active.file.name;ui.date.textContent=metadata.uploadedAt?new Date(metadata.uploadedAt).toLocaleString('es-MX'):'-';ui.status.textContent=`Active · v${metadata.version||1}`;state[`${kind}ActiveMetadata`]=metadata;return active}catch(error){ui.status.textContent='Connection error';toast(`${kind==='plan'?'Production Plan':'Employees'}: ${error.message}`,true);throw error}}
async function replaceActiveResource(kind,file){if(!file)return;const ui=activeUi(kind);ui.status.textContent=navigator.onLine?`Validando ${file.size.toLocaleString('es-MX')} bytes…`:'Guardando sin conexión…';try{if(kind==='plan'){state.pendingProductionImport=null;state.pendingProductionFile=null;$('#productionImportPreview').hidden=true;$('#applyProductionImport').disabled=true;const parsed=await loadFile(file,kind,false);let preview=null;try{preview=await stageProductionPlan(file,parsed)}catch(error){ui.status.textContent=`Supabase rechazó ${file.size.toLocaleString('es-MX')} bytes`;toast(error.message,true);updateSyncStatus();return}if(preview){state.pendingProductionFile=file;ui.name.textContent=file.name;ui.date.textContent=new Date().toLocaleString('es-MX');ui.status.textContent=importStatusLabel(preview.status);toast('Archivo validado. Revisa la vista previa antes de aplicar.');updateSyncStatus();return}const active=await dataService.replaceProductionPlan(file);ui.name.textContent=file.name;ui.date.textContent=new Date().toLocaleString('es-MX');ui.status.textContent=active?.metadata?.pendingSync?'Pendiente de sincronizar':'Respaldo activo';toast(`${file.name} guardado en el respaldo configurado`);updateSyncStatus();return}const active=await dataService.replaceEmployeeDatabase(file),parsed=await loadFile(file,kind,false);let supabaseResult=null;if(dataService.importEmployeeDatabase)supabaseResult=await dataService.importEmployeeDatabase(file,parsed);ui.name.textContent=file.name;ui.date.textContent=new Date().toLocaleString('es-MX');ui.status.textContent=active?.metadata?.pendingSync||supabaseResult?.pendingSync?'Pendiente de sincronizar':'Guardado';toast(active?.metadata?.pendingSync||supabaseResult?.pendingSync?`${file.name} guardado; se sincronizará cuando haya conexión`:`${file.name} guardado como archivo activo`);updateSyncStatus()}catch(error){ui.status.textContent='No se pudo guardar';toast(error.message,true)}}
async function refreshActiveResources(){const results=await Promise.allSettled([fetchActiveResource('plan'),fetchActiveResource('employees')]);try{const pending=await dataService.getPendingProductionPlanImport?.();if(pending)await renderProductionImportPreview(pending)}catch(error){console.warn('No fue posible restaurar la importación pendiente de Production Plan:',error)}return results}
function initProductionPlanRealtime(){
  if(productionPlanRealtimeInit)return productionPlanRealtimeInit;
  productionPlanRealtimeInit=(async()=>{
    const previous=productionPlanRealtimeSubscription;productionPlanRealtimeSubscription=null;
    if(previous)await previous.unsubscribe();
    if(!dataService.subscribeToProductionPlanChanges)return null;
    productionPlanRealtimeSubscription=await dataService.subscribeToProductionPlanChanges(()=>{
      clearTimeout(realtimePlanReloadTimer);
      realtimePlanReloadTimer=setTimeout(async()=>{try{await fetchActiveResource('plan');toast('Production Plan actualizado automáticamente desde Supabase')}catch(error){toast(`No fue posible actualizar el plan: ${error.message}`,true)}},400);
    });
    return productionPlanRealtimeSubscription;
  })().finally(()=>{productionPlanRealtimeInit=null});
  return productionPlanRealtimeInit;
}
