function prepareSignatureCanvas(canvas){const context=canvas.getContext('2d');context.lineWidth=2.2;context.lineCap='round';context.strokeStyle='#102f46';let drawing=false,dirty=false;const point=event=>{const rect=canvas.getBoundingClientRect(),source=event.touches?.[0]||event;return{x:(source.clientX-rect.left)*canvas.width/rect.width,y:(source.clientY-rect.top)*canvas.height/rect.height}};const start=event=>{event.preventDefault();drawing=true;dirty=true;const p=point(event);context.beginPath();context.moveTo(p.x,p.y)};const move=event=>{if(!drawing)return;event.preventDefault();const p=point(event);context.lineTo(p.x,p.y);context.stroke()};const stop=()=>drawing=false;canvas.addEventListener('pointerdown',start);canvas.addEventListener('pointermove',move);window.addEventListener('pointerup',stop);return{clear(){context.clearRect(0,0,canvas.width,canvas.height);dirty=false},isEmpty:()=>!dirty,dataUrl:()=>canvas.toDataURL('image/png')}}
function signatureEmployeeSource(department){const key=normalizeColumnName(department),scoped=state.employees.filter(employee=>[employee.area,employee.department].some(value=>normalizeColumnName(value).replace(/[^a-z0-9]+/g,' ').split(/\s+/).includes(key))),base=key==='npi'?[...state.npiEmployees,...scoped]:key==='efm'?[...EFM_EMPLOYEES,...scoped]:scoped;return[...new Map(base.map(employee=>[normalizeColumnName(employee.employeeNumber||employee.fullName),employee])).values()]}
function matchingSignatureEmployees(value,department=$('#signatureDialog')?.control?.dataset.department||''){const terms=normalizeColumnName(value).split(/\s+/).filter(Boolean);if(!terms.length)return[];return signatureEmployeeSource(department).filter(employee=>{const searchable=normalizeColumnName([employee.employeeNumber,employee.fullName].filter(Boolean).join(' '));return terms.every(term=>searchable.includes(term))})}
function employeeByQuery(value,department){const key=normalizeColumnName(value),matches=matchingSignatureEmployees(value,department);return matches.find(employee=>normalizeColumnName(employee.employeeNumber)===key||normalizeColumnName(employee.fullName)===key)||(matches.length===1?matches[0]:null)}
