function bindSignatureAutocomplete(){const input=$('#signatureEmployeeNumber');if(!input||$('#signatureEmployeeSuggestions'))return;const results=document.createElement('div');results.id='signatureEmployeeSuggestions';results.className='signature-employee-suggestions';results.hidden=true;input.parentElement.appendChild(results);const close=()=>{results.hidden=true;results.innerHTML=''};const render=()=>{const department=$('#signatureDialog')?.control?.dataset.department,matches=matchingSignatureEmployees(input.value,department).slice(0,10);if(!normalizeColumnName(input.value)){close();return}if(!matches.length){results.innerHTML='<div class="signature-suggestion-empty">Sin coincidencias</div>';results.hidden=false;return}results.innerHTML=matches.map((employee,index)=>`<button type="button" class="signature-suggestion" data-index="${index}"><strong>${escapeHtml([employee.employeeNumber,employee.fullName].filter(Boolean).join(' · '))}</strong><small>${escapeHtml([employee.area||employee.department,employee.shift,employee.position].filter(Boolean).join(' · '))}</small></button>`).join('');results.hidden=false;results.querySelectorAll('.signature-suggestion').forEach(button=>button.onclick=()=>{const employee=matches[Number(button.dataset.index)];input.value=employee.employeeNumber||employee.fullName;close();input.dispatchEvent(new Event('change',{bubbles:true}))})};input.addEventListener('input',render);input.addEventListener('focus',render);input.addEventListener('keydown',event=>{if(event.key==='Escape')close()});document.addEventListener('click',event=>{if(event.target!==input&&!results.contains(event.target))close()})}
