function initMaterialPlanAutofill(){document.addEventListener('production-record-selected',()=>{const form=$('.generator-form[data-type="material"]'),values=selectedValues();if(!form)return;for(const name of['internalModel','customerModel','rolling','line','materialType'])if(form.elements[name])form.elements[name].value=values[name]||'';toast('Datos generales del plan cargados en Material Delivery')})}
function refreshMaterialLookup(){const list=$('#materialRollingOptions');if(!list)return;const unique=new Map();state.plan.filter(record=>npiRollings(record).length).forEach(record=>{const rolling=String(record.rolling||record.orderNo||'').trim();if(rolling&&!unique.has(rolling))unique.set(rolling,record)});list.innerHTML=[...unique].map(([rolling,record])=>`<option value="${escapeHtml(rolling)}" label="${escapeHtml(record.internalModel||record.customerModel||'')}"></option>`).join('');const help=$('#materialRollingHelp');if(help)help.textContent=unique.size?`${unique.size.toLocaleString()} Rolling con PE DOC. NPI`:'No se encontraron Rolling asociados a PE DOC. NPI'}
function bindMaterialLookup(){const form=$('.generator-form[data-type="material"]');if(!form)return;const rolling=form.elements.rolling,model=form.elements.internalModel,help=$('#materialRollingHelp');const apply=()=>{const query=normalizeColumnName(rolling.value),matches=state.plan.filter(record=>npiRollings(record).length&&normalizeColumnName(record.rolling||record.orderNo)===query);$('#materialModelOptions').innerHTML=[...new Map(matches.map(record=>[record.internalModel,record])).keys()].filter(Boolean).map(value=>`<option value="${escapeHtml(value)}"></option>`).join('');const selected=matches.find(record=>!model.value||normalizeColumnName(record.internalModel)===normalizeColumnName(model.value))||matches[0];if(!selected){if(help)help.textContent=state.plan.length?'Rolling no encontrado entre los registros PE DOC. NPI':'Production Plan no disponible';return}model.value=selected.internalModel||'';form.elements.customerModel.value=selected.customerModel||'';form.elements.line.value=selected.line||'';form.elements.materialType.value=selected.materialType||'';state.currentProductionRecord=selected;state.selectedSchedule=selected.schedules?.[0]||null;if(help)help.textContent=`Rolling encontrado · PE DOC.: ${npiRollings(selected).join(', ')}`};rolling.addEventListener('input',apply);rolling.addEventListener('change',apply);model.addEventListener('change',apply);refreshMaterialLookup()}
function localToday(){const date=new Date();date.setMinutes(date.getMinutes()-date.getTimezoneOffset());return date.toISOString().slice(0,10)}
async function loadNpiEmployees(){try{const response=await fetch('data/npi-employees.xlsx?v=13',{cache:'no-store'});if(!response.ok)throw new Error(`HTTP ${response.status}`);const file=new File([await response.blob()],'Lista de PE-NPI.xlsx',{type:'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'}),parsed=await readEmployeeDatabase(file);state.npiEmployees=parsed.rows;console.info(`[NPI] ${state.npiEmployees.length} integrantes cargados desde Excel`);toast(`Base NPI lista · ${state.npiEmployees.length} integrantes`)}catch(error){console.warn('Se usa el catálogo NPI integrado porque no se pudo leer el Excel:',error);toast(`Base NPI lista · ${state.npiEmployees.length} integrantes`)}}
function bindFriendlyControls(){$$('.quantity-control').forEach(control=>control.querySelectorAll('button').forEach(button=>button.onclick=()=>{const input=control.querySelector('input');button.dataset.qtyAction==='increase'?input.stepUp():input.stepDown();if(Number(input.value)<0)input.value=0;input.dispatchEvent(new Event('input',{bubbles:true}))}));$$('.date-control').forEach(control=>{const input=control.querySelector('input');control.querySelector('.date-calendar').onclick=()=>{if(typeof input.showPicker==='function')input.showPicker();else{input.focus();input.click()}};control.querySelector('.date-today').onclick=()=>{input.value=localToday();input.dispatchEvent(new Event('change',{bubbles:true}))}})}
function formMarkup(type){
  const isMaterial=type==='material',v=selectedValues(),today=localToday();
  const fields=isMaterial
    ?materialFormFields(v,today)
    :`<label>Rolling<input name="rolling" value="${escapeHtml(v.rolling)}"></label><label>Order No.<input name="order" value="${escapeHtml(v.order)}"></label><label>Material Code<input name="material" value="${escapeHtml(v.material)}"></label><label>Internal Model<input name="internalModel" value="${escapeHtml(v.internalModel)}"></label><label>Customer Model<input name="customerModel" value="${escapeHtml(v.customerModel)}"></label><label>Date<input name="date" type="date" value="${today}"></label><label>Shift<select name="shift"><option>1st</option><option>2nd</option><option>3rd</option></select></label><label>Loss Time (min)<input name="lossTime" type="number" min="0"></label><label>Reason<input name="reason"></label><label>Employee<select name="employee"><option value="">Seleccionar empleado</option>${state.employees.slice(0,1000).map(e=>{const text=[e.employeeNumber,e.fullName,e.area].filter(Boolean).join(' · ');return`<option value="${escapeHtml(text)}">${escapeHtml(text)}</option>`}).join('')}</select></label><label class="span-2">Notes<textarea name="notes"></textarea></label>`;
  return `<div class="panel record-form"><div class="form-hero"><div><h2>${getFormConfig(type).name}</h2><p>Los datos del plan seleccionado se completan automaticamente.</p></div><label class="btn btn-light" style="border:1px solid var(--line)">Usar otra plantilla<input class="template-input" data-type="${type}" type="file" accept=".xlsx,.xlsm" hidden></label></div><form class="form-body generator-form" data-type="${type}"><div class="notice">${state.currentProductionRecord?'Orden del plan vinculada. Revisa los datos antes de generar el archivo.':'No hay una orden seleccionada. Puedes capturar los campos manualmente o elegir un registro en Production Plan.'}</div>${isMaterial?fields:`<div class="fields">${fields}</div>`}<div class="form-actions"><button class="btn btn-light" type="reset" style="border:1px solid var(--line)">Limpiar</button><button class="btn btn-primary" type="submit">Generar archivo Excel</button></div></form></div>`
}
function renderForms(){$('#materialView').innerHTML=formMarkup('material');bindMaterialLookup();bindSignatureControls();bindFriendlyControls();bindEvidenceControls();initModelChangeForm();$$('.template-input').forEach(input=>input.onchange=async e=>{const file=e.target.files[0];try{await dataService.uploadTemplate(file,input.dataset.type);state.templates[input.dataset.type]=await file.arrayBuffer();toast('Plantilla personalizada lista')}catch(err){toast(err.message||'No fue posible leer la plantilla',true)}});$$('.generator-form').forEach(form=>form.onsubmit=async e=>{e.preventDefault();const values=Object.fromEntries(new FormData(form));values.prefix=preferences.get().prefix;try{const file=await generateExcel(form.dataset.type,values,state.templates[form.dataset.type]),reportId=form.dataset.reportId||'';await dataService.saveGeneratedFile(file,{type:form.dataset.type,order:values.order||values.rolling||'',values,reportId,changeSummary:reportId?'ActualizaciÃ³n desde el historial':''});downloadFile(file);await updateStats();if(reportId){delete form.dataset.reportId;form.querySelector('.notice').textContent='Nueva versiÃ³n guardada. Puedes continuar capturando un reporte nuevo.';form.querySelector('[type=submit]').textContent='Generar archivo Excel'}toast(reportId?'Nueva versiÃ³n guardada en Supabase':'Archivo Excel guardado y generado correctamente')}catch(err){toast(err.message,true)}})}

function loadMaterialReportForEditing(item){const form=$('.generator-form[data-type="material"]');if(!form)return;for(const[name,value]of Object.entries(item.values||{})){const input=form.elements[name];if(!input)continue;if(input.type==='checkbox')input.checked=value!==undefined&&value!==null&&value!==''&&value!==false;else input.value=value??'';if(input.type==='hidden'&&input.closest('.signature-control')){const control=input.closest('.signature-control');try{const signature=JSON.parse(input.value);if(signature?.kind==='signature'){control.classList.add('signed');control.querySelector('small').textContent=`${signature.employeeNumber} Â· ${signature.fullName}`;control.querySelector('button').textContent='Cambiar firma'}}catch{}}}form.dataset.reportId=item.id;form.querySelector('.notice').innerHTML=`Editando <strong>${escapeHtml(item.reportNumber)}</strong> Â· versiÃ³n ${escapeHtml(item.version)}. Al guardar se crearÃ¡ una nueva versiÃ³n.`;form.querySelector('[type=submit]').textContent='Guardar nueva versiÃ³n';navigate('material');form.scrollIntoView({behavior:'smooth',block:'start'});toast(`Reporte ${item.reportNumber} abierto para ediciÃ³n`)}
document.addEventListener('reset',event=>{const form=event.target;if(!form.matches?.('.generator-form[data-type="material"]'))return;delete form.dataset.reportId;setTimeout(()=>{form.querySelector('.notice').textContent='Formulario limpio. El siguiente guardado crearÃ¡ un reporte nuevo.';form.querySelector('[type=submit]').textContent='Generar archivo Excel';form.querySelectorAll('.signature-control').forEach(control=>{control.classList.remove('signed');control.querySelector('small').textContent='Sin firma';control.querySelector('button').textContent='Firmar'})})})

function filteredHistoryItems(){const query=normalizeColumnName($('#historySearch')?.value||'');if(!query)return historyItems;return historyItems.filter(item=>[item.order,item.reportNumber,item.name,item.internalModel,item.customerModel,item.line].some(value=>normalizeColumnName(value).includes(query)))}
function paintHistory(){const items=filteredHistoryItems(),box=$('#historyList'),query=$('#historySearch')?.value.trim()||'';$('#historyMeta').textContent=query?`${items.length.toLocaleString('es-MX')} de ${historyItems.length.toLocaleString('es-MX')} archivos encontrados`:`${historyItems.length.toLocaleString('es-MX')} archivos disponibles`;box.innerHTML=items.length?items.map(x=>`<div class="history-item"><span class="file-icon">X</span><div><strong>${escapeHtml(x.reportNumber||x.name)}</strong><small>${new Date(x.date).toLocaleString('es-MX')} · ${x.type==='material'?'Material Delivery':'Model Change'}${x.order?' · Rolling '+escapeHtml(x.order):''}${x.version?' · v'+escapeHtml(x.version):''}</small></div><div class="history-actions">${x.type==='material'?`<button class="btn btn-light history-edit" data-id="${x.id}">Editar</button>`:''}<button class="btn btn-primary history-download" data-id="${x.id}">Descargar</button>${historyCanDelete?`<button class="btn history-delete" data-id="${x.id}">Eliminar</button>`:''}</div></div>`).join(''):`<div class="empty">${query?'No hay archivos que coincidan con ese Rolling.':'Aún no hay archivos generados.'}</div>`;box.querySelectorAll('.history-edit').forEach(button=>button.onclick=()=>loadMaterialReportForEditing(historyItems.find(x=>x.id===button.dataset.id)));box.querySelectorAll('.history-download').forEach(button=>button.onclick=async()=>{const item=historyItems.find(x=>x.id===button.dataset.id);try{if(item.storagePath&&dataService.downloadGeneratedReport)downloadFile(await dataService.downloadGeneratedReport(item));else if(item.file)downloadFile(item.file);else if(item.downloadUrl)window.open(item.downloadUrl,'_blank','noopener');else if(item.values){const file=await generateExcel(item.type,item.values,state.templates[item.type]);downloadFile(file)}else throw new Error('El archivo no tiene una URL de descarga.');toast('Descarga iniciada')}catch(e){toast(e.message,true)}});box.querySelectorAll('.history-delete').forEach(button=>button.onclick=async()=>{const item=historyItems.find(x=>x.id===button.dataset.id);if(!item||!confirm(`¿Eliminar definitivamente ${item.reportNumber||item.name}${item.order?` · Rolling ${item.order}`:''}?\n\nEsta acción no se puede deshacer.`)||!await confirmDeletePassword())return;button.disabled=true;button.textContent='Eliminando…';try{await dataService.deleteGeneratedFile(item);historyItems=historyItems.filter(record=>record.id!==item.id);paintHistory();$('#fileCount').textContent=historyItems.length;$('#recentFiles').innerHTML=historyItems.length?historyItems.slice(0,4).map(x=>`<div class="history-item"><span class="file-icon">X</span><div><strong>${escapeHtml(x.reportNumber||x.name)}</strong><small>${new Date(x.date).toLocaleString('es-MX')}</small></div></div>`).join(''):'Aún no hay archivos generados.';toast('Archivo eliminado definitivamente')}catch(error){button.disabled=false;button.textContent='Eliminar';toast(error.message,true)}})}
async function renderHistory(reload=true){if(reload){historyItems=await dataService.getGeneratedFiles();const auth=await dataService.getAuthState?.();historyCanDelete=auth?auth.role==='admin':true}paintHistory();$('#recentFiles').innerHTML=historyItems.length?historyItems.slice(0,4).map(x=>`<div class="history-item"><span class="file-icon">X</span><div><strong>${escapeHtml(x.reportNumber||x.name)}</strong><small>${new Date(x.date).toLocaleString('es-MX')}</small></div></div>`).join(''):'Aún no hay archivos generados.';return historyItems}
async function updateStats(){const items=await renderHistory();$('#fileCount').textContent=items.length}
function setConnection(message,type='neutral'){const status=$('#connectionStatus'),dot=$('#connectionDot');status.textContent=message;dot.className=`status-dot ${type}`}
async function updateSyncStatus(detail){const badge=$('#syncBadge');if(!badge)return;const storedPending=await dataService.getPendingCount?.();const pending=detail?.pending??storedPending??0;badge.className='sync-badge';if(!navigator.onLine){badge.textContent=pending?`Sin conexión · ${pending} pendiente${pending===1?'':'s'}`:'Sin conexión';badge.classList.add('offline')}else if(pending){badge.textContent=`${pending} pendiente${pending===1?'':'s'}`;badge.classList.add('pending')}else{badge.textContent='Sincronizado'}}
async function synchronizeNow(){if(!navigator.onLine){updateSyncStatus();return}const badge=$('#syncBadge');if(badge){badge.textContent='Sincronizando…';badge.className='sync-badge syncing'}try{const result=await dataService.syncPending?.();await updateSyncStatus(result);if(result?.synced)toast(`${result.synced} cambio${result.synced===1?'':'s'} sincronizado${result.synced===1?'':'s'}`)}catch(error){if(badge){badge.textContent='Error de sincronización';badge.className='sync-badge error'}console.error(error)}}
function initOfflineSupport(){document.addEventListener('offline-sync-change',event=>updateSyncStatus(event.detail));window.addEventListener('offline',()=>{updateSyncStatus();setConnection('Sin conexión','error')});window.addEventListener('online',()=>{setConnection('Internet disponible','ok');synchronizeNow()});if('serviceWorker'in navigator)navigator.serviceWorker.register('./service-worker.js').catch(error=>console.warn('No se pudo instalar el modo offline:',error));updateSyncStatus();if(navigator.onLine)synchronizeNow();setInterval(async()=>{if(navigator.onLine&&(await dataService.getPendingCount?.()))synchronizeNow()},30000)}
async function renderRemoteSignature(token,apiUrl){document.body.innerHTML=`<main class="remote-sign-page"><section class="signature-dialog remote-sign-card"><div class="brand"><span class="brand-mark">NPI</span><div><strong>NPI DIGITAL</strong><small>Firma de documento</small></div></div><div id="remoteSignatureContent"><div class="empty">Consultando solicitud…</div></div></section></main>`;const box=$('#remoteSignatureContent');if(!apiUrl){box.innerHTML='<div class="notice error">El enlace no contiene la configuración del servicio.</div>';return}const service=createDataService({serviceMode:'google',apiUrl});try{const request=await service.getSignatureRequest(token);if(request.status!=='pending'){box.innerHTML=`<div class="notice">Esta solicitud está ${request.status==='signed'?'firmada':'vencida'}.</div>`;return}box.innerHTML=`<span class="eyebrow">${escapeHtml(request.department)}</span><h2>Firma requerida</h2><p>Verifica tus datos y firma dentro del recuadro.</p><div class="signature-employee"><strong>${escapeHtml(request.fullName)}</strong><span>${escapeHtml(request.employeeNumber)} · ${escapeHtml(request.area||'')} · ${escapeHtml(request.position||'')}</span></div><canvas id="remoteSignatureCanvas" width="700" height="240"></canvas><div class="signature-actions"><button class="btn btn-light" id="remoteClear" type="button">Limpiar</button><button class="btn btn-primary" id="remoteSubmit" type="button">Confirmar firma</button></div><div id="remoteStatus"></div>`;const pad=prepareSignatureCanvas($('#remoteSignatureCanvas'));$('#remoteClear').onclick=()=>pad.clear();$('#remoteSubmit').onclick=async()=>{if(pad.isEmpty())return $('#remoteStatus').textContent='Dibuja tu firma antes de continuar.';$('#remoteSubmit').disabled=true;$('#remoteStatus').textContent='Guardando firma…';try{await service.submitSignature(token,pad.dataUrl());box.innerHTML='<div class="signature-success"><strong>Firma recibida</strong><p>Ya puedes cerrar esta página.</p></div>'}catch(error){$('#remoteSubmit').disabled=false;$('#remoteStatus').textContent=error.message}}}catch(error){box.innerHTML=`<div class="notice error">${escapeHtml(error.message)}</div>`}}
function initSettings(){const form=$('#settingsForm'),s=preferences.get();Object.entries(s).forEach(([k,v])=>{if(form.elements[k])form.elements[k].value=v});$('#serviceModeLabel').textContent=s.serviceMode==='google'?'Google Drive / Sheets':'Almacenamiento temporal';setConnection(s.apiUrl?'Not tested':'Not configured');form.onsubmit=async e=>{e.preventDefault();const value=Object.fromEntries(new FormData(form));preferences.save(value);dataService=createDataService(value);$('#serviceModeLabel').textContent=value.serviceMode==='google'?'Google Drive / Sheets':'Almacenamiento temporal';setConnection(value.apiUrl?'Not tested':'Not configured');toast('Configuracion guardada. Servicio actualizado.')};$('#testConnection').onclick=async()=>{const value=Object.fromEntries(new FormData(form)),service=createDataService(value);setConnection('Testing...');try{const result=await service.testConnection();setConnection(result.message||'Connected','ok')}catch(e){setConnection('Connection failed','error');toast(e.message,true)}};$('#historySearch').oninput=()=>renderHistory(false);$('#refreshHistory').onclick=async()=>{try{await updateStats();toast('Historial actualizado')}catch(e){toast(e.message,true)}}}
const SUPABASE_ACTIVATION_KEY='npi_supabase_activation_test_v1';
function activationControls(){let button=$('#supabaseActivationTest'),result=$('#supabaseActivationResult');if(!button){button=document.createElement('button');button.className='btn btn-primary';button.id='supabaseActivationTest';button.type='button';button.textContent='Probar activación';$('#supabaseSignOut').parentElement.appendChild(button);result=document.createElement('div');result.id='supabaseActivationResult';result.className='notice';button.parentElement.after(result)}return{button,result}}
function showActivationResult(value,error=false){const{result}=activationControls();result.hidden=false;result.className=`notice${error?' error':''}`;result.textContent=typeof value==='string'?value:JSON.stringify(value,null,2)}
function testEmployeeFilters(rows){const sample=rows.find(employee=>employee.employeeNumber&&employee.shift&&employee.line)||rows[0],search=$('#employeeSearch'),shift=$('#shiftFilter'),line=$('#employeeLineFilter');search.value=String(sample.employeeNumber).slice(0,Math.max(2,String(sample.employeeNumber).length-1));search.dispatchEvent(new Event('input',{bubbles:true}));const searchMatches=state.employeeFiltered.some(employee=>employee.id===sample.id);search.value='';search.dispatchEvent(new Event('input',{bubbles:true}));if(sample.shift&&[...shift.options].some(option=>option.value===String(sample.shift))){shift.value=String(sample.shift);shift.dispatchEvent(new Event('change',{bubbles:true}))}const shiftMatches=state.employeeFiltered.length>0;shift.value='';shift.dispatchEvent(new Event('change',{bubbles:true}));if(sample.line&&[...line.options].some(option=>option.value===String(sample.line))){line.value=String(sample.line);line.dispatchEvent(new Event('change',{bubbles:true}))}const lineMatches=state.employeeFiltered.length>0;line.value='';line.dispatchEvent(new Event('change',{bubbles:true}));return{searchMatches,shiftMatches,lineMatches}}
async function startSupabaseActivationTest(){const{button}=activationControls();button.disabled=true;showActivationResult('Creando y editando empleado temporal con la sesión autenticada…');try{const auth=await dataService.getAuthState();if(!auth.authenticated||auth.plantCode!=='MAIN'||auth.role!=='admin')throw new Error('La sesión no está reconocida como administrador de MAIN.');const employees=await dataService.getEmployees();if(employees?.source!=='supabase'||employees.rows.length!==646)throw new Error(`Se esperaban 646 empleados desde Supabase; se obtuvieron ${employees?.rows?.length??0} desde ${employees?.source||'ningún origen'}.`);const employeeNumber=`ACTIVATION-${Date.now()}`,created=await dataService.createEmployee({employeeNumber,fullName:'SUPABASE ACTIVATION TEMP',shift:'TEST',line:'TEST',area:'TEST',sourceData:{activationTest:true}},{queueOnFailure:false}),edited=await dataService.updateEmployee(created.id,{fullName:'SUPABASE ACTIVATION TEMP EDITED',position:'TEMPORAL'},{queueOnFailure:false});localStorage.setItem(SUPABASE_ACTIVATION_KEY,JSON.stringify({phase:'edited',id:edited.id,employeeNumber,startedAt:new Date().toISOString(),auth,initialEmployees:employees.rows.length}));showActivationResult('Creación y edición correctas. La página se recargará para comprobar persistencia.');setTimeout(()=>location.reload(),800)}catch(error){showActivationResult(error.message,true);button.disabled=false}}
async function resumeSupabaseActivationTest(){const saved=JSON.parse(localStorage.getItem(SUPABASE_ACTIVATION_KEY)||'null');if(!saved||saved.phase!=='edited')return;const{button}=activationControls();button.disabled=true;showActivationResult('Comprobando persistencia, filtros, desactivación y carga del archivo fuente…');try{const auth=await dataService.getAuthState(),employees=await dataService.getEmployees(),persisted=employees?.rows.find(employee=>employee.id===saved.id&&employee.fullName==='SUPABASE ACTIVATION TEMP EDITED');if(!persisted)throw new Error('El empleado temporal no persistió después de recargar.');const filters=testEmployeeFilters(employees.rows);if(!Object.values(filters).every(Boolean))throw new Error('Falló una prueba de búsqueda o filtros.');await dataService.updateEmployee(saved.id,{isActive:false},{queueOnFailure:false});const afterDeactivate=await dataService.getEmployees();if(afterDeactivate.rows.some(employee=>employee.id===saved.id))throw new Error('El empleado temporal continúa activo.');const response=await fetch('data/employees.xlsx',{cache:'no-store'});if(!response.ok)throw new Error(`No se pudo leer employees.xlsx: HTTP ${response.status}`);const file=new File([await response.blob()],'employees.xlsx',{type:'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'}),parsed=await readEmployeeDatabase(file),upload=await dataService.importEmployeeDatabase(file,parsed);if(!upload?.ok)throw new Error(upload?.error||'La carga del archivo fuente quedó pendiente.');const completed={phase:'complete',completedAt:new Date().toISOString(),authenticated:auth.authenticated,email:auth.email,plant:auth.plantCode,role:auth.role,employeesFromSupabase:saved.initialEmployees,created:true,edited:true,persistedAfterReload:true,deactivated:true,filters,sourceFileUploaded:true,sourceVersion:upload.version,imported:upload.imported,skills:upload.skills,tempEmployeeId:saved.id,tempEmployeeNumber:saved.employeeNumber};localStorage.setItem(SUPABASE_ACTIVATION_KEY,JSON.stringify(completed));showActivationResult(completed);toast('Pruebas de activación Supabase completadas')}catch(error){showActivationResult(error.message,true)}finally{button.disabled=false}}
async function initSupabaseAuth(){
  const status=$('#supabaseStatus'),dot=$('#supabaseDot'),signIn=$('#supabaseSignIn'),signOut=$('#supabaseSignOut'),email=$('#supabaseEmail'),password=$('#supabasePassword');
  if(!status)return;
  const{button}=activationControls();
  const paint=async()=>{
    const auth=await dataService.getAuthState?.()||{configured:false,authenticated:false},activation=JSON.parse(localStorage.getItem(SUPABASE_ACTIVATION_KEY)||'null');
    status.textContent=!auth.configured?'No configurado':auth.authenticated?`Sesión permanente activa · ${auth.email} · ${auth.plantCode||'sin planta'} · ${auth.role||'sin rol'}`:'Configurado · inicia sesión una sola vez';
    dot.className=`status-dot ${auth.authenticated?'ok':'neutral'}`;
    email.closest('label').hidden=auth.authenticated;
    password.closest('label').hidden=auth.authenticated;
    signIn.hidden=auth.authenticated;
    signOut.hidden=!auth.authenticated;
    signIn.disabled=!auth.configured;
    signOut.disabled=!auth.authenticated;
    button.disabled=!auth.authenticated||activation?.phase==='complete';
  };
  signIn.onclick=async()=>{signIn.disabled=true;try{await dataService.signIn(email.value,password.value);password.value='';await paint();await fetchActiveResource('employees');toast('Sesión permanente de Supabase iniciada')}catch(error){toast(error.message,true)}finally{signIn.disabled=false}};
  signOut.onclick=async()=>{try{await dataService.signOut();await paint();await fetchActiveResource('employees');toast('Sesión de Supabase cerrada; se usa el respaldo configurado')}catch(error){toast(error.message,true)}};
  button.onclick=startSupabaseActivationTest;
  const previous=JSON.parse(localStorage.getItem(SUPABASE_ACTIVATION_KEY)||'null');
  if(previous?.phase==='complete')showActivationResult(previous);
  const subscription=dataService.onAuthStateChange?.(()=>setTimeout(async()=>{try{await paint();await initProductionPlanRealtime()}catch(error){toast(error.message,true)}},0));
  if(subscription)window.addEventListener('pagehide',()=>subscription.unsubscribe(),{once:true});
  await paint();
}

function restoreEvidencePreviews(form){form?.querySelectorAll('.evidence-control').forEach(control=>{const input=control.querySelector('input[type=hidden]'),picker=control.querySelector('.evidence-picker span');try{const evidence=JSON.parse(input.value);paintEvidence(control,evidence?.kind==='evidence'?evidence:null);picker.textContent=evidence?.kind==='evidence'?'Cambiar foto':'Subir foto'}catch{paintEvidence(control,null);picker.textContent='Subir foto'}})}
document.addEventListener('click',event=>{if(event.target.closest?.('.history-edit'))setTimeout(()=>restoreEvidencePreviews($('.generator-form[data-type="material"]')))})
document.addEventListener('reset',event=>{if(!event.target.matches?.('.generator-form[data-type="material"]'))return;setTimeout(()=>restoreEvidencePreviews(event.target))})

function ensureEmployeeDialog(){let dialog=$('#employeeDialog');if(dialog)return dialog;dialog=document.createElement('div');dialog.id='employeeDialog';dialog.className='employee-modal';dialog.hidden=true;dialog.innerHTML=`<div class="employee-dialog"><button class="employee-dialog-close" type="button" aria-label="Cerrar">×</button><h2>Agregar empleado</h2><p>El empleado quedará disponible en todos los dispositivos y en las firmas de su departamento.</p><form id="employeeCreateForm"><div class="employee-form-grid"><label>Número de empleado<input name="employeeNumber" required autocomplete="off"></label><label>Nombre completo<input name="fullName" required autocomplete="off"></label><label>Departamento<select name="department" required><option value="">Seleccionar…</option><option>QM</option><option>PFA</option><option>EFM</option><option>NPI</option><option>PE</option><option>WH</option></select></label><label>Turno<input name="shift" autocomplete="off" placeholder="Ej. 01A"></label><label>Puesto<input name="position" autocomplete="off"></label><label>Línea<input name="line" autocomplete="off"></label></div><div class="employee-form-status" hidden></div><div class="employee-form-actions"><button class="btn btn-light employee-cancel" type="button">Cancelar</button><button class="btn btn-primary" type="submit">Guardar empleado</button></div></form></div>`;document.body.appendChild(dialog);const close=()=>{dialog.hidden=true;dialog.querySelector('.employee-form-status').hidden=true};dialog.querySelector('.employee-dialog-close').onclick=close;dialog.querySelector('.employee-cancel').onclick=close;dialog.onclick=event=>{if(event.target===dialog)close()};const form=dialog.querySelector('form');form.onsubmit=async event=>{event.preventDefault();const submit=form.querySelector('[type=submit]'),status=form.querySelector('.employee-form-status'),values=Object.fromEntries(new FormData(form));submit.disabled=true;status.hidden=false;status.className='employee-form-status';status.textContent='Guardando en Supabase…';try{if(!dataService.createEmployee)throw new Error('La base de empleados de Supabase no está configurada.');const auth=await dataService.getAuthState?.();if(!auth?.authenticated)throw new Error('Inicia sesión en Supabase antes de agregar empleados.');if(!['admin','editor'].includes(auth.role))throw new Error('Tu cuenta necesita permiso de administrador o editor.');const department=String(values.department||'').trim().toUpperCase(),created=await dataService.createEmployee({...values,employeeNumber:String(values.employeeNumber||'').trim(),fullName:String(values.fullName||'').trim().toUpperCase(),department,area:department});await fetchActiveResource('employees');form.reset();dialog.hidden=true;toast(created.pendingSync?'Empleado guardado; se sincronizará al recuperar conexión':'Empleado agregado a Supabase')}catch(error){status.className='employee-form-status error';status.textContent=error.message}finally{submit.disabled=false}};return dialog}
function initEmployeeManager(){const actions=$('#employeesView .section-heading .top-actions');if(!actions||$('#addEmployee'))return;const button=document.createElement('button');button.id='addEmployee';button.className='btn btn-primary';button.type='button';button.textContent='Agregar empleado';button.onclick=()=>{const dialog=ensureEmployeeDialog();dialog.hidden=false;dialog.querySelector('[name=employeeNumber]').focus()};actions.insertBefore(button,actions.firstChild)}
document.addEventListener('DOMContentLoaded',initEmployeeManager)

document.addEventListener('DOMContentLoaded',async()=>{const params=new URLSearchParams(location.search),signatureToken=params.get('sign');if(signatureToken){await renderRemoteSignature(signatureToken,params.get('api'));return}injectEmployeeStyles();$('#today').textContent=new Intl.DateTimeFormat('es-MX',{dateStyle:'long'}).format(new Date());initNavigation();initImports();initPersistentResourceHandlers();initSettings();await initSupabaseAuth();await initProductionPlanRealtime();initOfflineSupport();initMaterialPlanAutofill();await loadNpiEmployees();renderForms();await refreshActiveResources();await resumeSupabaseActivationTest();try{const templates=await dataService.getTemplates();for(const item of templates){if(item.file)state.templates[item.type]=await item.file.arrayBuffer()}await updateStats()}catch(e){toast(e.message,true)}});
